// Parallel execution with plain callbacks is messy
let results = [];
let completed = 0;

function parallelComplete(data) {
  results.push(data);
  completed++;
  if (completed === 3) {
    console.log('All done!', results);
  }
}

fetchA(parallelComplete);
fetchB(parallelComplete);
fetchC(parallelComplete);
// This is exactly why Promise.all() was invented.
